namespace sv_b5a07ceb6b5b4affa6152452fc36349e.Models;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@rendermode InteractiveServer
@using sv_b5a07ceb6b5b4affa6152452fc36349e.Models
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container d-flex">
    @* ───── Left Sidebar (Filters) ───── *@
    <aside class="catalog-sidebar p-3 border-end">
        <h5>Filters</h5>

        @* Category checkboxes *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Category</label>
            @if (_categories is not null)
            {
                @foreach (var cat in _categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                               checked="@_selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                    </div>
                }
            }
        </div>

        @* Price range *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Price Range</label>
            <div class="d-flex gap-2">
                <input type="number" class="form-control form-control-sm" placeholder="Min"
                       @bind="_minPrice" @bind:event="oninput" min="0" />
                <input type="number" class="form-control form-control-sm" placeholder="Max"
                       @bind="_maxPrice" @bind:event="oninput" min="0" />
            </div>
        </div>

        @* In stock only *@
        <div class="form-check mb-3">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   @bind="_inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>

        <div class="d-grid gap-2">
            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    @* ───── Main Content ───── *@
    <main class="catalog-main flex-grow-1 p-3">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info text-center my-5" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 text-nowrap" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm w-auto"
                            @bind="_sortBy" @bind:after="LoadProductsAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    Showing @(_startItem)–@(_endItem) of @_result.TotalCount products
                </span>
            </div>

            @* Product Grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductClick="HandleProductClick"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @if (_totalPages > 1)
            {
                <nav class="mt-4" aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                    disabled="@(_currentPage == 1)">
                                Previous
                            </button>
                        </li>
                        @foreach (var p in PageNumbers())
                        {
                            <li class="page-item @(p == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == _totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                    disabled="@(_currentPage == _totalPages)">
                                Next
                            </button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </main>
</div>

@code {
    private const int PageSize = 9;

    // Filter state
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Results state
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    private int _startItem => _result is null || _result.Items.Count == 0
        ? 0
        : (_result.Page - 1) * _result.PageSize + 1;

    private int _endItem => _result is null
        ? 0
        : (_result.Page - 1) * _result.PageSize + _result.Items.Count;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = LoadProductsCoreAsync();
            await Task.WhenAll(categoriesTask, productsTask);
            _categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            await LoadProductsCoreAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProductsCoreAsync()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );

        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
    }

    private void ToggleCategory(string category, bool selected)
    {
        if (selected)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        _sortBy = "price_asc";
        await LoadProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await LoadProductsAsync();
    }

    private IEnumerable<int> PageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, _currentPage - maxVisible / 2);
        int end = Math.Min(_totalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);
        return Enumerable.Range(start, end - start + 1);
    }

    private void HandleProductClick(Product product)
    {
        // Parent / routing logic can be customized here
    }

    private void HandleAddToCart(Product product)
    {
        // Cart logic placeholder
    }
}

.catalog-container {
    min-height: calc(100vh - 4rem);
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    background-color: var(--bs-light, #f8f9fa);
}

.catalog-main {
    width: 75%;
}

@using sv_b5a07ceb6b5b4affa6152452fc36349e.Models

<div class="card h-100 product-card" @onclick="OnCardClick" role="button">
    <div class="card-img-placeholder d-flex align-items-center justify-content-center bg-secondary-subtle">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @((MarkupString)GetStars(Product.Rating))
        </div>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnCartClick"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductClick { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private static string GetStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }

    private async Task OnCardClick() => await OnProductClick.InvokeAsync(Product);
    private async Task OnCartClick() => await OnAddToCart.InvokeAsync(Product);
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 .25rem .75rem rgba(0, 0, 0, .15);
    transform: translateY(-2px);
}

.card-img-placeholder {
    height: 180px;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

